// Devuelve el catálogo de stock + historial de movimientos.
// Filtros opcionales por query-string:
//   ?q=<texto>                (contains sobre nombre/sku/categoria)
//   ?categoria=<cat>          (match exacto)
//   ?estado_stock=ok|bajo|agotado   (calculado: stock_actual vs stock_minimo)
//   ?articulo_id=<uuid>       (si viene: devuelve sólo ese artículo con su historial)
//   ?incluir_archivadas=1
const wh = $('Webhook GET Stock').first().json || {};
const q = wh.query || wh.params || {};
const verArch = String(q.incluir_archivadas || '') === '1';

// Los dos nodos Supabase vuelcan items a las entradas en orden. En code
// node con dos inputs cada $input.all() devuelve los de la entrada por
// defecto. Para acceder al segundo input usamos $('GET Movimientos Supabase').
const articulos = ($('GET Stock Supabase').all() || [])
  .map(i => i.json)
  .filter(x => x && x.id && (verArch || !x.deleted_at));
const movimientos = ($('GET Movimientos Supabase').all() || [])
  .map(i => i.json)
  .filter(x => x && x.id);

// Helper: estado del stock relativo al mínimo.
function estadoStock(a) {
  const cur = Number(a.stock_actual) || 0;
  const min = Number(a.stock_minimo) || 0;
  if (cur === 0) return 'agotado';
  if (min > 0 && cur <= min) return 'bajo';
  return 'ok';
}

let out = articulos.map(a => ({ ...a, estado_stock: estadoStock(a) }));

if (q.q) {
  const needle = String(q.q).toLowerCase();
  out = out.filter(a =>
    String(a.nombre || '').toLowerCase().includes(needle) ||
    String(a.sku || '').toLowerCase().includes(needle) ||
    String(a.categoria || '').toLowerCase().includes(needle)
  );
}
if (q.categoria)     out = out.filter(a => a.categoria === q.categoria);
if (q.estado_stock)  out = out.filter(a => a.estado_stock === q.estado_stock);
if (q.articulo_id) {
  out = out.filter(a => a.id === q.articulo_id);
}

// Orden: agotados y bajos primero (para llamar la atención), luego ok;
// dentro por nombre asc. Archivados al final.
const orderEstado = { agotado: 0, bajo: 1, ok: 2 };
out.sort((a, b) => {
  const ax = a.deleted_at ? 1 : 0;
  const bx = b.deleted_at ? 1 : 0;
  if (ax !== bx) return ax - bx;
  const oa = orderEstado[a.estado_stock] ?? 9;
  const ob = orderEstado[b.estado_stock] ?? 9;
  if (oa !== ob) return oa - ob;
  return String(a.nombre || '').localeCompare(String(b.nombre || ''), 'es');
});

// Para cada artículo adjuntamos su historial (si el caller lo pidió
// concreto o por si lo quiere todo de un tirón). El historial va
// ordenado por created_at DESC (recientes primero).
const movsByArt = {};
movimientos.forEach(m => {
  if (!movsByArt[m.articulo_id]) movsByArt[m.articulo_id] = [];
  movsByArt[m.articulo_id].push(m);
});
Object.values(movsByArt).forEach(arr => arr.sort((a, b) => new Date(b.created_at) - new Date(a.created_at)));
out = out.map(a => ({ ...a, movimientos: movsByArt[a.id] || [] }));

// Totales agregados sobre el listado filtrado (sólo vivos):
const totales = out.filter(a => !a.deleted_at).reduce((acc, a) => {
  acc.articulos   += 1;
  acc.unidades    += Number(a.stock_actual) || 0;
  acc.valor_compra += (Number(a.stock_actual) || 0) * (Number(a.precio_compra) || 0);
  acc.valor_venta  += (Number(a.stock_actual) || 0) * (Number(a.precio_venta)  || 0);
  if (a.estado_stock === 'bajo')    acc.bajos++;
  if (a.estado_stock === 'agotado') acc.agotados++;
  return acc;
}, { articulos: 0, unidades: 0, valor_compra: 0, valor_venta: 0, bajos: 0, agotados: 0 });
totales.valor_compra = +totales.valor_compra.toFixed(2);
totales.valor_venta  = +totales.valor_venta.toFixed(2);

return [{ json: { articulos: out, totales } }];

// Acciones soportadas:
//   create      → alta de artículo (opcional stock_inicial > 0 genera movimiento 'entrada')
//   update      → edición de campos del catálogo (no toca stock_actual directamente — se hace vía movimiento)
//   archivar    → soft-delete (deleted_at=now)
//   reactivar   → deshace archivar
//   movimiento  → inserta en hardware_stock_movimientos (trigger actualiza stock_actual)
const raw = $input.first().json || {};
const b = (raw.body && typeof raw.body === 'object') ? raw.body : raw;
const action = String(b.action || '').toLowerCase();
const a = b.articulo || {};
const m = b.movimiento || {};
const now = new Date().toISOString();
const errores = [];
const VALID = ['create', 'update', 'archivar', 'reactivar', 'movimiento'];
if (!VALID.includes(action)) errores.push('action inválida: ' + action);
if (['update','archivar','reactivar'].includes(action) && !a.id) errores.push('id obligatorio para ' + action);
if (action === 'movimiento' && !m.articulo_id) errores.push('articulo_id obligatorio para movimiento');

const UUID_RE = /^[0-9a-f]{8}-[0-9a-f]{4}-[0-9a-f]{4}-[0-9a-f]{4}-[0-9a-f]{12}$/i;
if (a.id && !UUID_RE.test(a.id))              errores.push('articulo.id no es un UUID válido');
if (m.articulo_id && !UUID_RE.test(m.articulo_id)) errores.push('movimiento.articulo_id no es un UUID válido');

const CATEGORIAS = ['tablet','soporte','cargador','cable','impresora','cajon','balanza','lector','router','otro'];
const TIPOS_MOV  = ['entrada','salida','ajuste'];

function validaNumero(v, nombre, min, max, entero) {
  if (v === undefined || v === null || v === '') return undefined;
  const n = +v;
  if (!Number.isFinite(n)) { errores.push(nombre + ' debe ser número'); return undefined; }
  if (entero && !Number.isInteger(n)) { errores.push(nombre + ' debe ser entero'); return undefined; }
  if (n < min || n > max)  { errores.push(nombre + ' fuera de rango (' + min + '..' + max + ')'); return undefined; }
  return n;
}
function genUuid() { return 'xxxxxxxx-xxxx-4xxx-yxxx-xxxxxxxxxxxx'.replace(/[xy]/g, function(c){ const r = Math.random()*16|0; return (c==='x'?r:(r&0x3)|0x8).toString(16); }); }

let out = {};
let path = 'hardware_stock';
let extra = null; // para movimiento derivado de create con stock_inicial > 0

if (action === 'create') {
  if (!a.nombre || !String(a.nombre).trim()) errores.push('nombre obligatorio');
  if (a.categoria && !CATEGORIAS.includes(a.categoria)) errores.push('categoria inválida');
  const stock_inicial = validaNumero(a.stock_inicial, 'stock_inicial', 0, 1000000, true);
  const stock_minimo  = validaNumero(a.stock_minimo,  'stock_minimo',  0, 1000000, true);
  const pc = validaNumero(a.precio_compra, 'precio_compra', 0, 99999999.99, false);
  const pv = validaNumero(a.precio_venta,  'precio_venta',  0, 99999999.99, false);
  const _uuid = genUuid();
  out = {
    id: _uuid,
    nombre: String(a.nombre || '').trim(),
    sku: a.sku != null ? String(a.sku).trim() || null : null,
    categoria: a.categoria || 'otro',
    descripcion: a.descripcion != null ? String(a.descripcion) : null,
    unidad: a.unidad != null ? String(a.unidad).trim() || 'ud' : 'ud',
    // stock_actual arranca a 0; si viene stock_inicial>0 generamos un
    // movimiento 'entrada' aparte (así queda trazado en el historial).
    stock_actual: 0,
    stock_minimo: stock_minimo !== undefined ? stock_minimo : 0,
    precio_compra: pc !== undefined ? pc : 0,
    precio_venta:  pv !== undefined ? pv : 0,
    proveedor: a.proveedor != null ? String(a.proveedor).trim() || null : null,
    ubicacion: a.ubicacion != null ? String(a.ubicacion).trim() || null : null,
    notas: a.notas != null ? String(a.notas) : null,
    created_by: a.created_by ? String(a.created_by) : null,
    created_at: now,
    updated_at: now
  };
  if (stock_inicial && stock_inicial > 0) {
    extra = {
      __extra: true,
      __path: 'hardware_stock_movimientos',
      articulo_id: _uuid,
      tipo: 'entrada',
      cantidad: stock_inicial,
      motivo: 'Stock inicial',
      created_by: a.created_by ? String(a.created_by) : null,
      created_at: now
    };
  }
} else if (action === 'update') {
  out.id = a.id;
  if (a.nombre !== undefined) {
    const v = a.nombre == null ? '' : String(a.nombre).trim();
    if (!v) errores.push('nombre no puede ser vacío');
    else out.nombre = v;
  }
  if (a.sku !== undefined)         out.sku         = a.sku != null && String(a.sku).trim() ? String(a.sku).trim() : null;
  if (a.categoria !== undefined) {
    if (!CATEGORIAS.includes(a.categoria)) errores.push('categoria inválida');
    else out.categoria = a.categoria;
  }
  if (a.descripcion !== undefined) out.descripcion = a.descripcion != null ? String(a.descripcion) : null;
  if (a.unidad !== undefined)      out.unidad      = a.unidad != null && String(a.unidad).trim() ? String(a.unidad).trim() : 'ud';
  if (a.stock_minimo !== undefined){ const n = validaNumero(a.stock_minimo, 'stock_minimo', 0, 1000000, true); if (n !== undefined) out.stock_minimo = n; }
  if (a.precio_compra !== undefined){ const n = validaNumero(a.precio_compra, 'precio_compra', 0, 99999999.99, false); if (n !== undefined) out.precio_compra = n; }
  if (a.precio_venta  !== undefined){ const n = validaNumero(a.precio_venta,  'precio_venta',  0, 99999999.99, false); if (n !== undefined) out.precio_venta  = n; }
  if (a.proveedor !== undefined)   out.proveedor   = a.proveedor != null && String(a.proveedor).trim() ? String(a.proveedor).trim() : null;
  if (a.ubicacion !== undefined)   out.ubicacion   = a.ubicacion != null && String(a.ubicacion).trim() ? String(a.ubicacion).trim() : null;
  if (a.notas !== undefined)       out.notas       = a.notas != null ? String(a.notas) : null;
  out.updated_at = now;
} else if (action === 'archivar') {
  out = { id: a.id, deleted_at: now, updated_at: now };
} else if (action === 'reactivar') {
  out = { id: a.id, deleted_at: null, updated_at: now };
} else if (action === 'movimiento') {
  path = 'hardware_stock_movimientos';
  if (m.tipo && !TIPOS_MOV.includes(m.tipo)) errores.push('tipo debe ser entrada|salida|ajuste');
  const cantidad = validaNumero(m.cantidad, 'cantidad', 1, 1000000, true);
  if (cantidad === undefined) errores.push('cantidad obligatoria (> 0)');
  out = {
    id: genUuid(),
    articulo_id: m.articulo_id,
    tipo: m.tipo,
    cantidad: cantidad,
    delta_ajuste: (m.tipo === 'ajuste' && m.delta_ajuste !== undefined) ? +m.delta_ajuste : null,
    motivo: m.motivo != null ? String(m.motivo) : null,
    pedido_id: m.pedido_id && UUID_RE.test(m.pedido_id) ? m.pedido_id : null,
    created_by: m.created_by ? String(m.created_by) : null,
    created_at: now
  };
}

Object.keys(out).forEach(k => { if (out[k] === undefined) delete out[k]; });

if (errores.length > 0) {
  return [{ json: { __error: true, __errores: errores, __action: action } }];
}

// Para create: si hay extra (stock_inicial), emitimos 2 items — el
// segundo se rutea por el mismo httpRequest con path distinto.
const _method = (action === 'create' || action === 'movimiento') ? 'POST' : 'PATCH';
const _qs = (action === 'create' || action === 'movimiento') ? 'on_conflict=id' : ('id=eq.' + encodeURIComponent(a.id || ''));
const primary = Object.assign({}, out, { __method: _method, __qs: _qs, __path: path, __action: action });
if (extra) {
  const extraOut = Object.assign({}, extra);
  delete extraOut.__extra;
  extraOut.__method = 'POST';
  extraOut.__qs     = 'on_conflict=id';
  // id para el movimiento
  extraOut.id = genUuid();
  return [{ json: primary }, { json: extraOut }];
}
return [{ json: primary }];

// Normaliza la salida PostgREST al shape único del frontend:
//   { success, articulo, movimiento, errores }
// Cuando la acción es `create` + stock_inicial > 0 hay 2 items (articulo
// + movimiento). Devolvemos el artículo (primera fila) en `articulo`.
const prep = $('Preparar').first().json || {};
if (prep.__error) {
  return [{ json: { success: false, articulo: null, movimiento: null, errores: prep.__errores || ['validación falló'] } }];
}
const items = $input.all() || [];
const errores = [];
const rows = [];
for (const it of items) {
  const j = it.json; if (!j) continue;
  if (Array.isArray(j)) { rows.push(...j); continue; }
  if (j.code && j.message && !j.id) { errores.push(j.message + (j.details ? ' (' + j.details + ')' : '')); continue; }
  if (j.error) { errores.push(String(j.error.message || j.error)); continue; }
  if (j.id) rows.push(j);
  if (Array.isArray(j.data)) rows.push(...j.data);
}
if (rows.length === 0 && errores.length === 0) errores.push('PostgREST devolvió 0 filas');

// Primera fila: el artículo si acción toca hardware_stock, o movimiento
// si acción es 'movimiento'. El frontend discrimina por action.
const action = prep.__action;
let articulo = null, movimiento = null;
if (action === 'movimiento') {
  movimiento = rows[0] || null;
} else {
  articulo = rows[0] || null;
  // Si hubo stock_inicial movimiento, row[1] es el movimiento.
  if (rows.length >= 2) movimiento = rows[1];
}
return [{ json: {
  success: rows.length > 0,
  articulo,
  movimiento,
  errores
} }];
